const raw = $input.item.json.choices[0].message.content;
let analysis;
try {
  const match = raw.match(/```json([\s\S]*?)```/) || raw.match(/(\{[\s\S]*\})/);
  analysis = JSON.parse(match ? match[1].trim() : raw.trim());
} catch(e) {
  analysis = {
    patterns_positive: [],
    patterns_negative: [],
    parameter_insights: [],
    suggested_direction: 'Explorar variaciones del benchmark actual',
    strategies_to_prioritize: ['breakout', 'vwap_pullback']
  };
}
return [{json: {analysis, raw_response: raw}}];

const raw = $input.item.json.choices[0].message.content;
const REQUIRED = {
  breakout: ['lookback','vol_ratio_min','atr_period','sl_atr_mult','trail_atr_mult','ema_trend_period','ema_trend_daily_period','adx_filter','breakeven_after_r'],
  vwap_pullback: ['sl_atr_mult','trail_atr_mult','adx_filter','vol_ratio_min','breakeven_after_r','ema_trend_period','ema_trend_daily_period'],
  mean_reversion: ['rsi_period','rsi_oversold','bb_period','bb_std','atr_period','sl_atr_mult','ema_trend_period']
};
const BOUNDS = {
  lookback: [10,40], vol_ratio_min: [1.0,3.0], adx_filter: [0,35],
  ema_trend_daily_period: [15,60], breakeven_after_r: [0,1.5],
  sl_atr_mult: [0.75,4.0], trail_atr_mult: [1.5,4.0], rsi_oversold: [25,40]
};
let configs;
try {
  const match = raw.match(/```json([\s\S]*?)```/) || raw.match(/(\[[\s\S]*\])/);
  configs = JSON.parse(match ? match[1].trim() : raw.trim());
} catch(e) { return [{json: {valid_configs: [], skipped: 0, reason: 'JSON parse error'}}]; }
const valid = configs.filter(c => {
  if (!['breakout','vwap_pullback','mean_reversion'].includes(c.strategy)) return false;
  const req = REQUIRED[c.strategy] || [];
  if (!req.every(p => p in (c.params||{}))) return false;
  for (const [p, v] of Object.entries(c.params||{})) {
    if (BOUNDS[p] && (v < BOUNDS[p][0] || v > BOUNDS[p][1])) return false;
  }
  return true;
});
return [{json: {valid_configs: valid, total: configs.length, skipped: configs.length - valid.length}}];
